const c="http://3.139.202.192:3000";async function d({search:a="",filters:t={},page:o=1,limit:i=7}){try{const r=new URLSearchParams({search:a||"",page:String(o),limit:String(i)});Object.keys(t).forEach(n=>{const s=t[n];Array.isArray(s)&&s.length>0&&r.append(n,s.join(","))});const e=await(await fetch(`${c}/api/public/datasets?${r.toString()}`)).json();return{total:e.total||0,totalPages:e.totalPages||1,data:e.data||[]}}catch{return{data:[],total:0,totalPages:1}}}async function u(a){try{const t=await fetch(`${c}/api/public/datasets/${a}`);if(!t.ok)throw new Error("Error obteniendo detalles del dataset");return(await t.json()).data}catch(t){return console.error("Error en getPublicDatasetById:",t),null}}export{u as a,d as g};
